request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?node ?type ?name WHERE {
  ?node tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "0b21c69687b64d8886fb7cc5dc56ff6c" .
  ?node a ?type .
  FILTER(?type IN (bboExt:ChoreographyTask, bboExt:StartEvent, bboExt:EndEvent, bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  OPTIONAL { ?node bbo:name ?name . }

  # Check if there is any outgoing sequence flow
  FILTER NOT EXISTS {
    ?flow a bbo:SequenceFlow ;
          bbo:has_sourceRef ?node .
  }
}
